package com.hospital.management.controller.admin;import com.hospital.management.model.*;import com.hospital.management.service.*;import org.junit.jupiter.api.Test;import javax.servlet.RequestDispatcher;import javax.servlet.http.*;import java.util.*;import static org.mockito.Mockito.*;
class AdminAndDepartmentServletTest{@Test void adminForwards()throws Exception{HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);RequestDispatcher d=mock(RequestDispatcher.class);when(q.getServletPath()).thenReturn("/admin/");when(q.getRequestDispatcher(any())).thenReturn(d);new AdminHomeServlet().doGet(q,r);verify(d).forward(q,r);}@Test void listDefaults()throws Exception{DepartmentService s=mock(DepartmentService.class);when(s.listDepartments(any())).thenReturn(new Page<>(List.of(),1,10,0));HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);RequestDispatcher d=mock(RequestDispatcher.class);when(q.getRequestDispatcher(any())).thenReturn(d);new DepartmentListServlet(s).doGet(q,r);verify(s).listDepartments(argThat(p->p.getPageNumber()==1&&p.getPageSize()==10));}@Test void invalidStatusActionIsBadRequest()throws Exception{DepartmentService s=mock(DepartmentService.class);HttpServletRequest q=mock(HttpServletRequest.class);HttpServletResponse r=mock(HttpServletResponse.class);when(q.getParameter("departmentId")).thenReturn("1");when(q.getParameter("action")).thenReturn("delete");new DepartmentStatusServlet(s).doPost(q,r);verify(r).sendError(400);}}
